class Solution:
    def maxSumOfSquares(self, num, sum):
        if sum > 9 * num:
            return ""
        digits = []
        remaining = sum
        for i in range(num):
            spots_after = num - 1 - i
            d = min(9, remaining)
            low = remaining - 9 * spots_after
            if low > d:
                d = low
            digits.append(str(d))
            remaining -= d
        return "".join(digits)

