class Solution:
    def maxSumOfSquares(self, num, sum):
        if sum > 9 * num:
            return ""
        out = []
        remaining = sum
        for i in range(num):
            d = 9 if remaining >= 9 else remaining
            out.append(chr(48 + d))
            remaining -= d
        return "".join(out)

