var maxSumOfSquares = function(num, sum) {
    if (sum > 9 * num) return "";
    const out = [];
    let remaining = sum;
    for (let i = 0; i < num; i++) {
        const d = remaining >= 9 ? 9 : remaining;
        out.push(String.fromCharCode(48 + d));
        remaining -= d;
    }
    return out.join('');
};
